@timeline-prefix-cls: ~"@{ant-prefix}-timeline";
@timeline-color: @border-color-split;

.@{timeline-prefix-cls} {
  list-style: none;
  margin: 0;
  padding: 0;

  &-item {
    position: relative;
    padding: 0 0 12px;
    list-style: none;
    margin: 0;

    &-tail {
      position: absolute;
      left: 5px;
      top: 0;
      height: 100%;
      border-left: 2px solid @timeline-color;
    }

    &-pending &-tail {
      display: none;
    }

    &-head {
      position: absolute;
      width: 12px;
      height: 12px;
      background-color: @component-background;
      border-radius: 100px;
      border: 2px solid transparent;
      &-blue {
        border-color: @primary-color;
        color: @primary-color;
      }
      &-red {
        border-color: @error-color;
        color: @error-color;
      }
      &-green {
        border-color: @success-color;
        color: @success-color;
      }
    }

    &-head-custom {
      position: absolute;
      text-align: center;
      width: 40px;
      left: -14px;
      line-height: 1;
      margin-top: 6px;
      border: 0;
      height: auto;
      border-radius: 0;
      padding: 3px 0;
      font-size: @font-size-base;
      transform: translateY(-50%);
    }

    &-content {
      padding: 0 0 10px 24px;
      font-size: @font-size-base;
      position: relative;
      top: -3px;
    }

    &-last {
      .@{timeline-prefix-cls}-item-tail {
        border-left: 2px dotted @timeline-color;
        display: none;
      }
      .@{timeline-prefix-cls}-item-content {
        min-height: 48px;
      }
    }
  }

  &&-pending &-item-last &-item-tail {
    display: block;
  }
}

@import "../../style/themes/default";
@import "../../style/mixins/index";

@slider-prefix-cls: ~"@{ant-prefix}-slider";

.@{slider-prefix-cls} {
  position: relative;
  margin: 14px 6px 10px;
  padding: 4px 0;
  height: 12px;
  cursor: pointer;
  touch-action: none;

  &-rail {
    position: absolute;
    width: 100%;
    height: 4px;
    border-radius: 2px;
    background-color: @background-color-base;
    transition: background-color @animation-duration-base;
  }

  &-track {
    position: absolute;
    height: 4px;
    border-radius: @border-radius-base;
    background-color: @primary-color;
    transition: background-color @animation-duration-base;
  }

  &-handle {
    position: absolute;
    width: 14px;
    height: 14px;
    margin-top: -5px;
    margin-left: -7px;
    border-radius: 50%;
    border: 2px solid @primary-color;
    background-color: @component-background;
    cursor: pointer;
    transition: border-color @animation-duration-base, transform @animation-duration-base @ease-in-out;

    &:hover {
      border-color: @primary-5;
      transform: scale(1.2);
    }

    &:focus {
      outline: none;
      box-shadow: 0 0 0 5px fade(@primary-color, 20%);
    }
  }

  &-disabled {
    cursor: not-allowed;

    .@{slider-prefix-cls}-track {
      background-color: @disabled-color !important;
    }

    .@{slider-prefix-cls}-handle {
      border-color: @disabled-color !important;
      cursor: not-allowed;

      &:hover {
        transform: none;
      }
    }

    .@{slider-prefix-cls}-rail {
      background-color: @background-color-base;
    }
  }

  &-vertical {
    width: 12px;
    height: 100%;
    margin: 6px 10px;
    padding: 0 4px;

    .@{slider-prefix-cls}-rail {
      width: 4px;
      height: 100%;
    }

    .@{slider-prefix-cls}-track {
      width: 4px;
      position: absolute;
      bottom: 0;
    }

    .@{slider-prefix-cls}-handle {
      margin-left: -5px;
      margin-bottom: -7px;
    }
  }
}

