//
// List groups
// --------------------------------------------------

// Base class
//
// Easily usable on <ul>, <ol>, or <div>.
.list-group {
  // No need to set list-style: none; since .list-group-item is block level
  margin-bottom: 20px;
  padding-left: 0; // reset padding because ul and ol
}

// Individual list items
// -------------------------

.list-group-item {
  position: relative;
  display: block;
  padding: 10px 15px;
  // Place the border on the list items and negative margin up for better styling
  margin-bottom: -1px;
  background-color: @list-group-bg;
  border: 1px solid @list-group-border;

  // Round the first and last items
  &:first-child {
    .border-top-radius(@list-group-border-radius);
  }
  &:last-child {
    margin-bottom: 0;
    .border-bottom-radius(@list-group-border-radius);
  }

  // Align badges within list items
  > .badge {
    float: right;
  }
  > .badge + .badge {
    margin-right: 5px;
  }
}

// Linked list items
a.list-group-item {
  color: @list-group-link-color;

  .list-group-item-heading {
    color: @list-group-link-heading-color;
  }

  // Hover state
  &:hover,
  &:focus {
    text-decoration: none;
    background-color: @list-group-hover-bg;
  }

  // Active class on item itself, not parent
  &.active,
  &.active:hover,
  &.active:focus {
    z-index: 2; // Place active items above their siblings for proper border styling
    color: @list-group-active-color;
    background-color: @list-group-active-bg;
    border-color: @list-group-active-border;

    // Force color to inherit for custom content
    .list-group-item-heading {
      color: inherit;
    }
    .list-group-item-text {
      color: lighten(@list-group-active-bg, 40%);
    }
  }
}

// Custom content options
// -------------------------

.list-group-item-heading {
  margin-top: 0;
  margin-bottom: 5px;
}
.list-group-item-text {
  margin-bottom: 0;
  line-height: 1.3;
}

@import '../../base.less';

@import './_var.less';

.@{prefix}-textarea {
  display: flex;
  box-sizing: border-box;
  padding: @textarea-padding;
  background-color: @textarea-background-color;

  &--layout-vertical {
    flex-direction: column;
  }

  &__label:not(:empty) {
    font: @textarea-label-font;
    color: @textarea-label-color;
    flex-shrink: 0;
    margin-right: @spacer-2;
    width: @textarea-label-width;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;

    .@{prefix}-textarea--layout-vertical & {
      font: @font-body-medium;
      padding-bottom: @spacer;
    }
  }

  &__wrapper {
    display: flex;
    flex-direction: column;
    width: 100%;
    flex: 1 1 auto;
    overflow: hidden;

    &-inner {
      flex: 1 1 auto;
      box-sizing: border-box;
      width: inherit;
      min-width: 0;
      height: 100%;
      min-height: 20px;
      margin: 0;
      padding: 0;
      text-align: left;
      background-color: transparent;
      border: 0;
      outline: none;
      resize: none;
      font: @textarea-text-font;
      color: @textarea-text-color;
    }
  }

  &__placeholder {
    &::placeholder {
      color: @textarea-placeholder-color;
      font: @textarea-placeholder-font;
    }
  }

  &__indicator:not(:empty) {
    color: @textarea-indicator-text-color;
    font: @textarea-indicator-text-font;
    text-align: @textarea-indicator-text-align;
    padding-top: @textarea-indicator-text-padding-top;
  }

  &--border {
    border-radius: @textarea-border-radius;
    position: relative;

    &::after {
      content: '';
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      border: @textarea-border-width solid @textarea-border-color;
      border-radius: inherit;
      pointer-events: none;
    }
  }

  &--disabled {
    color: @textarea-disabled-text-color;
    cursor: not-allowed;
  }

  &--readonly {
    cursor: pointer;
  }
