		}

		&:hover {
			color: @crumb-selected-text !important;
			background-color: rgba(0, 0, 0, 0) !important;
		}

		&.selected {
			background-color: @crumb-selected-background !important;
			color: @crumb-selected-text !important;
			cursor: default;
		}

		&.collapsed {
			color: @global-text !important;
		}
	}
}

