@import "ui-variables.less";
@import "ui-mixins.less";
@import "octicon-mixins";

atom-workspace {
  .tree-view {
    .text(normal);
    font-size: @font-size;
    background: @tree-view-background-color;
    padding: 0;
    box-sizing: border-box;
    min-width: 100%;

    & > .directory {
      & > .header {
        transition: all @transition-time ease;
        background: @theme-concrete;
        height: @tab-height;
        line-height: @tab-height;

        & span {
          .text(bold);
          color: @theme-cement;
          transition: all @transition-time ease;

          &.icon:before {
            display: none;
          }
        }

        &:hover {
          & span {
            color: @text-color-highlight;
          }
        }

        &:before {
          visibility: hidden;
        }

        &:after {
          content: "hide";
          .text(subtle);
          background: @tab-background-color-hover;
          position: absolute;
          top: @tab-height/2 - 6px;
          right: @component-padding;
          padding-left: 2px;
          padding-right: 2px;
          border-radius: 2px;
          font-size: 10px;
          height: 12px;
          line-height: 12px;
          text-transform: uppercase;
          opacity: 0;
          transform: scale(0);
          transition: all @transition-time ease;
        }

        &:hover {
          background: @tab-background-color-hover;

          &:after {
            opacity: 1.0;
            transform: scale(1);
          }
        }
      }

      & > .entries {
        opacity: 1;
        padding-bottom: @component-padding;
        transition: all @transition-time ease;
      }
    }

    & > .directory.collapsed {
      & > .header {
        & span {
          color: @text-color-subtle;
        }

        &:hover {
          & span {
            color: @text-color-highlight;
          }
        }

        &:after {
          content: "show";
        }
      }

      & > .entries {
        display: block !important;
        padding-bottom: 0;
        opacity: 0;
      }
    }
  }
}

